  const  TitleProps = { title,href,count,icon}
  console.log(data);

  return (
    <div className='ProductSection'>
        <SubTitle {...TitleProps} />
      <div className='Cards'>
        <CardSwiper data={data}/>
      </div>

    </div>
  )
}

export default ProductSection
